    n = len(p)
    fail = [0] * n
    k = 0  # length of current longest prefix-suffix
    for i in range(1, n):
        while k > 0 and p[i] != p[k]:
            k = fail[k - 1]
        if p[i] == p[k]:
            k += 1
        fail[i] = k
    return fail
