def rle_encode(s: str) -> list[tuple[str, int]]:
    """Encode a string as a list of (character, count) pairs for maximal runs."""
    pairs: list[tuple[str, int]] = []
    for ch in s:
        if pairs and pairs[-1][0] == ch:
            pairs[-1] = (ch, pairs[-1][1] + 1)
        else:
            pairs.append((ch, 1))
    return pairs


def rle_decode(pairs) -> str:
    """Decode a list of (character, count) pairs back into a string.

    A count of 0 contributes nothing to the output.
    """
    return "".join(ch * count for ch, count in pairs)
